When launching a token for a DeFi project, there are a few options for handling the process of selling tokens privately to early investors and then adding them to a launchpad. One approach is to use a single smart contract to handle both processes. This can be done by adding functionality to the contract to allow for private token sales and then using a launchpad function to add those tokens to the public token supply.
Here's an example of how this might be implemented in Solidity:
```
pragma solidity ^0.8.0;
contract MyToken {
    // The basic token information, such as the name and symbol
    string public name = "My Token";
    string public symbol = "MTK";
    uint8 public decimals = 18;
    uint256 public totalSupply;
    // The private sale function, which allows a limited number of investors to purchase tokens at a discounted price
    function privateSale(address[] memory whitelist, uint256 discount) public payable {
        // Only allow whitelisted addresses to participate in the sale
        require(whitelist.length > 0, "No whitelisted addresses provided");
        require(msg.value >= 1 ether, "Insufficient ether sent");
        // Reduce the total supply by the number of purchased tokens
        totalSupply = totalSupply.sub(whitelist.length);
        // Discount the token price for whitelisted addresses
        uint256 discountPrice = totalSupply.div(uint256(whitelist.length)).add(discount);
        // Allow whitelisted addresses to purchase tokens at the discounted price
        for (address investor in whitelist) {
            buy(investor, discountPrice);
        }
    }
    // The launchpad function, which allows the purchased tokens to be added to the public token supply
    function launchpad(address tokenAddress) public {
        // Only allow the contract owner to add tokens to the launchpad
        require(msg.sender == owner, "Only the contract owner can add tokens to the launchpad");
        // Add the purchased tokens to the public token supply
        totalSupply = totalSupply.add(balanceOf(tokenAddress));
    }
    // The buy function, which allows a user to purchase tokens with ether
    function buy(address tokenAddress, uint256 amount) public payable {
        // Only allow addresses to purchase tokens with ether
        require(msg.sender.isContract(), "Only contracts can purchase tokens");
        // Only allow the contract owner to add tokens to the launchpad
        require(msg.sender == owner, "Only the contract owner can add tokens to the launchpad");
        // Add the purchased tokens to the user's balance
        balanceOf(tokenAddress)[msg.sender] = balanceOf(tokenAddress).sub(amount);
        // Add the purchased tokens to the contract's balance
        balanceOf[tokenAddress] = balanceOf[tokenAddress].add(amount);
        // Add the purchased tokens to the total supply
        totalSupply = totalSupply.add(amount);
        // Distribute the unsold tokens to the whitelist
        for (uint256 i = 0; i < whitelist.length; i++) {
            if (whitelist[i] != address(0)) {
                balanceOf[tokenAddress] = balanceOf[tokenAddress].sub(amount);
                whitelist[i] = address(0);
            }
        }
    }
}
```
In this example, the `privateSale` function allows a limited number of investors to purchase tokens at a discounted price. The `totalSupply` is reduced by the number of purchased tokens, and the `launchpad` function allows the purchased tokens to be added to the public token supply.
